Update `save_pending_deliveries()` and `load_pending_deliveries()`:

```rust
fn save_pending_deliveries(
    path: &Path,
    deliveries: &HashMap<String, DeliveryState>,
) -> Result<()> {
    let persisted: Vec<PersistedDelivery> = deliveries
        .values()
        .map(|state| PersistedDelivery {
            metadata: state.metadata.clone(),
            targets: state.targets.clone(),
        })
        .collect();
    let json = serde_json::to_string_pretty(&persisted)?;
    // ... atomic write with tempfile ...
    Ok(())
}

fn load_pending_deliveries(path: &Path) -> HashMap<String, DeliveryState> {
    let data = match std::fs::read_to_string(path) {
        Ok(d) => d,
        Err(_) => return HashMap::new(),
    };
    let persisted: Vec<PersistedDelivery> = match serde_json::from_str(&data) {
        Ok(v) => v,
        Err(e) => {
            tracing::warn!(error = %e, "failed parsing persisted deliveries");
            return HashMap::new();
        }
    };

    persisted
        .into_iter()
        .map(|p| {
            let id = p.metadata.delivery_id.clone();
            (
                id,
                DeliveryState {
                    metadata: p.metadata,
                    targets: p.targets,
                    next_retry_at: Instant::now(),  // Retry immediately on restart
                    attempts: 0,
                    backoff_multiplier: 1.0,
                },
            )
        })
        .collect()
}
```

